                    ['day_number' => 150, 'stage' => 'Tubérisation', 'action_name' => 'Buttage + entretien du paillage',           'type' => 'sarclage',      'product_suggested' => null,           'dose' => null,         'method' => 'buttage manuel', 'notes' => 'Butter de nouveau et entretenir le paillage pour favoriser le grossissement des rhizomes et éviter leur exposition à la lumière.'],
                    ['day_number' => 210, 'stage' => 'Récolte',    'action_name' => 'Récolte gingembre jeune (frais)',             'type' => 'recolte',       'product_suggested' => null,           'dose' => null,         'method' => 'arrachage manuel à la fourche', 'notes' => 'Pour le gingembre frais tendre, récolter dès 7 mois. Arracher délicatement à la fourche par temps sec sans casser les rhizomes. Laver et tenir à l\'ombre.'],
                    ['day_number' => 255, 'stage' => 'Récolte',    'action_name' => 'Récolte gingembre mûr (8-9 mois)',            'type' => 'recolte',       'product_suggested' => null,           'dose' => null,         'method' => 'arrachage + séchage', 'notes' => 'Récolter le gingembre mûr (fibreux, plus piquant, conservable) à 8-9 mois quand les feuilles jaunissent et sèchent. Arracher par temps sec, nettoyer, laisser ressuyer. Sécher les rhizomes destinés à la conservation/poudre. Conserver des éclats sains pour la plantation suivante.'],
