            ],
        ];

        foreach ($protocols as $data) {
            $items = $data['items'];
            unset($data['items']);
            $data['is_active'] = true;
            $data['agro_zone'] = null;

            $protocol = CropProtocol::updateOrCreate(['name' => $data['name']], $data);

            // Remplacement intégral des étapes (idempotence).
            $protocol->items()->delete();
            foreach ($items as $item) {
                $protocol->items()->create($item);
            }
        }
    }
